  export NODE_PATH="/testbed/node_modules/.pnpm/tsx@4.21.0/node_modules/tsx/dist/node_modules:/testbed/node_modules/.pnpm/tsx@4.21.0/node_modules/tsx/node_modules:/testbed/node_modules/.pnpm/tsx@4.21.0/node_modules:/testbed/node_modules/.pnpm/node_modules"
